import type { HostCssKey } from './types.ts'
import { hostCss, loadCss } from '@wippy-fe/proxy'

const DEFAULT_HOST_CSS_KEYS: HostCssKey[] = [
  'themeConfigUrl',
  'primeVueCssUrl',
  'markdownCssUrl',
  'iframeCssUrl',
]

/**
 * Loads host CSS URLs into the shadow root as `<style>` elements.
 * Non-blocking — returns a promise but the component doesn't need to await it.
 */
export function loadHostCss(shadow: ShadowRoot, keys?: HostCssKey[]): Promise<void> {
  const cssKeys = keys ?? DEFAULT_HOST_CSS_KEYS
  // Filter out keys whose URL is missing (e.g. removed CSS like fontCssUrl).
  // Load each independently so one failure doesn't block the rest.
  const jobs = cssKeys.map(async (key) => {
    const url = hostCss[key]
    if (!url) {
      console.warn(`[wippy-fe/webcomponent-core] hostCss key "${key}" is undefined — skipping. Remove it from hostCssKeys if the CSS was removed.`)
      return null
    }
    try {
      return await loadCss(url)
    }
    catch (err) {
      console.warn(`[wippy-fe/webcomponent-core] Failed to load hostCss "${key}" (${url}):`, err)
      return null
    }
  })
  return Promise.all(jobs).then((cssChunks) => {
    for (const css of cssChunks) {
      if (!css)
        continue
      const style = document.createElement('style')
      style.textContent = css
      style.setAttribute('role', '@wippy-fe/host-css')
      shadow.appendChild(style)
    }
  })
}

/**
 * Injects inline CSS text into the shadow root.
 */
export function injectInlineCss(shadow: ShadowRoot, text: string): void {
  const style = document.createElement('style')
  style.textContent = text
  shadow.appendChild(style)
}
