/**
 * Opt-in reactive adapter for `WippyElement`.
 *
 * Framework-agnostic primitive that lets non-Vue consumers subscribe to
 * prop / content updates and emit typed events on a web component without
 * pulling Vue (or any other reactivity library) into the core bundle.
 *
 * Access via `this.reactive` on a `WippyElement` subclass — the getter is
 * lazy, so subclasses that never touch it pay zero allocation cost. See
 * `base-element.ts:get reactive` for the bridge into the lifecycle.
 *
 * The `notifyProps` / `notifyContent` methods are package-visible: the
 * base element calls them from `attributeChangedCallback` and the content
 * MutationObserver callback respectively. They are NOT part of the public
 * API consumers should reach for.
 *
 * Cleanup: `dispose()` runs from `disconnectedCallback`. All listener
 * sets are cleared; subsequent notifyProps/notifyContent are no-ops; the
 * `events.emit` becomes a no-op too. A fresh adapter is allocated on the
 * next `this.reactive` access (i.e. after reconnect).
 */

export type PropsListener<Props> = (props: Props, errors: readonly string[]) => void
export type ContentListener = (content: string | null) => void

export interface SubscribeOptions {
  /** Cancel the subscription when the signal aborts. */
  signal?: AbortSignal
  /** Fire the listener once synchronously with the current value. */
  immediate?: boolean
}

export interface PropsSubscription<Props> {
  /** Current parsed props. Always reflects the latest state. */
  readonly value: Props
  /** Current validation/parse errors. */
  readonly errors: readonly string[]
  /**
   * Register a listener that fires whenever props change. Returns an
   * unsubscribe function. Pass `options.signal` for AbortSignal-driven
   * cleanup (e.g. tied to an element's lifetime). Pass
   * `options.immediate: true` to fire once synchronously with the current
   * value — useful when the subscriber is set up mid-flight.
   *
   * Note: `notifyProps` runs BEFORE the subclass `onPropsChanged()` hook.
   * A subscriber added from inside `onPropsChanged()` therefore does NOT
   * receive the currently-firing change — only the next one. Use
   * `{ immediate: true }` to also see the current value.
   */
  subscribe: (listener: PropsListener<Props>, options?: SubscribeOptions) => () => void
}

export interface ContentSubscription {
  /** Current `<template>` content text, or `null` if not set. */
  readonly value: string | null
  /** See `PropsSubscription.subscribe` for the same ordering caveat. */
  subscribe: (listener: ContentListener, options?: SubscribeOptions) => () => void
}

export interface EventEmitterHandle<Events> {
  /**
   * Dispatch a typed `CustomEvent` (bubbles + composed, identical
   * semantics to the protected `emitEvent` helper). The key is constrained
   * to `keyof Events & string`, so consumers narrow `Events` to get
   * autocomplete + payload-type checks.
   *
   * No-op after the adapter is disposed (i.e. after the element is
   * detached). The element is the only event target — subscribers on
   * the element itself receive the event.
   */
  emit: <K extends keyof Events & string>(event: K, detail: Events[K]) => void
}

export interface ReactiveAdapter<Props, Events> {
  props: PropsSubscription<Props>
  events: EventEmitterHandle<Events>
  /**
   * Present only when the element's `wippyConfig.contentTemplate` is set;
   * `null` otherwise. Avoids fake `.value === null` semantics for elements
   * that don't track children content.
   */
  content: ContentSubscription | null
}

/**
 * Concrete implementation used by `WippyElement`. The `notify*` methods
 * are intentionally exposed (not private) so the base-element can call
 * them; consumers should never reach for them.
 *
 * @internal
 */
export class ReactiveAdapterImpl<Props, Events> implements ReactiveAdapter<Props, Events> {
  private _props: Props
  private _errors: readonly string[]
  private _content: string | null
  private _propsListeners = new Set<PropsListener<Props>>()
  private _contentListeners = new Set<ContentListener>()
  private _disposed = false
  private _emitToDom: (eventName: string, detail?: unknown) => void

  readonly props: PropsSubscription<Props>
  readonly events: EventEmitterHandle<Events>
  readonly content: ContentSubscription | null

  constructor(
    initial: {
      props: Props
      errors: readonly string[]
      content: string | null
      hasContent: boolean
    },
    emitToDom: (eventName: string, detail?: unknown) => void,
  ) {
    this._props = initial.props
    this._errors = initial.errors
    this._content = initial.content
    this._emitToDom = emitToDom

    // Each getter / closure below runs with the surrounding object literal
    // as `this`, not the class instance — so we have to capture the
    // instance explicitly here.
    // eslint-disable-next-line ts/no-this-alias
    const self = this

    this.props = {
      get value() {
        return self._props
      },
      get errors() {
        return self._errors
      },
      subscribe(listener, options) {
        return self._subscribeProps(listener, options)
      },
    }

    this.events = {
      emit(event, detail) {
        if (self._disposed)
          return
        self._emitToDom(event as string, detail)
      },
    }

    this.content = initial.hasContent
      ? {
          get value() {
            return self._content
          },
          subscribe(listener, options) {
            return self._subscribeContent(listener, options)
          },
        }
      : null
  }

  /** @internal */
  notifyProps(props: Props, errors: readonly string[]): void {
    if (this._disposed)
      return
    this._props = props
    this._errors = errors
    for (const listener of this._propsListeners)
      listener(props, errors)
  }

  /** @internal */
  notifyContent(content: string | null): void {
    if (this._disposed)
      return
    this._content = content
    for (const listener of this._contentListeners)
      listener(content)
  }

  /** @internal */
  dispose(): void {
    if (this._disposed)
      return
    this._disposed = true
    this._propsListeners.clear()
    this._contentListeners.clear()
  }

  private _subscribeProps(listener: PropsListener<Props>, options?: SubscribeOptions): () => void {
    if (this._disposed || options?.signal?.aborted)
      return () => {}
    // Add to the set BEFORE firing `immediate` so a re-entrant
    // `notifyProps` triggered from inside the immediate callback can
    // find this listener and fire it for the synchronous change too.
    this._propsListeners.add(listener)
    if (options?.immediate)
      listener(this._props, this._errors)
    const unsub = () => {
      this._propsListeners.delete(listener)
      // Manual unsub must also detach the abort listener — otherwise it
      // accumulates on long-lived signals (e.g. an AbortController kept
      // around for the element's whole lifetime that fans out to many
      // subscriptions). `{ once: true }` only auto-removes when 'abort'
      // actually fires.
      options?.signal?.removeEventListener('abort', unsub)
    }
    options?.signal?.addEventListener('abort', unsub, { once: true })
    return unsub
  }

  private _subscribeContent(listener: ContentListener, options?: SubscribeOptions): () => void {
    if (this._disposed || options?.signal?.aborted)
      return () => {}
    this._contentListeners.add(listener)
    if (options?.immediate)
      listener(this._content)
    const unsub = () => {
      this._contentListeners.delete(listener)
      options?.signal?.removeEventListener('abort', unsub)
    }
    options?.signal?.addEventListener('abort', unsub, { once: true })
    return unsub
  }
}
