import type { ReactiveAdapter } from './reactive-adapter.ts'
import type { WippyElementConfig } from './types.ts'
import { addCollection } from '@iconify/vue'
import { addIcons, define } from '@wippy-fe/proxy'
import { injectInlineCss, loadHostCss } from './css-loader.ts'
import { getWippyHost } from './host-scope.ts'
import { parseProps } from './prop-parser.ts'
import { ReactiveAdapterImpl } from './reactive-adapter.ts'

/**
 * Abstract base class for Wippy web components.
 *
 * Generic over `Props` — the parsed prop object type. This types `onMount`,
 * `onPropsChanged`, and `validateProps`. Defaults to `Record<string, unknown>`.
 *
 * Lifecycle order (first connect):
 *   1. shadow DOM attached
 *   2. `onInit(shadow)` — hook for early shadow DOM customization
 *   3. inline CSS injected
 *   4. host CSS loading started (async, non-blocking)
 *   5. container div created and appended
 *   6. icons registered
 *   7. props parsed from attributes + custom validation
 *   8. `onMount(shadow, container, props, errors)` — framework setup
 *   9. internals state → ready
 *  10. `onReady()` — post-mount hook
 *  11. `load` event emitted
 *
 * On reconnect (move-style DOM op: detach → reattach), the shadow root
 * persists across the cycle, so steps 1, 3, 4, 5 (CSS injection +
 * container creation) are skipped to avoid duplicating `<style>` and
 * container `<div>` siblings inside the persistent shadow. The stored
 * container is reused and `onMount` is re-invoked with `isRemount = true`
 * so framework adapters can decide between fresh-mount and remount paths.
 *
 * On error: `onError(error)` → internals state → error → `error` event
 * On disconnect: `onUnmount()` → `unload` event → internals cleared.
 * Note: `disconnectedCallback` does NOT clear the shadow root or the
 * stored container — they're reused on reconnect.
 */
export abstract class WippyElement<
  Props = Record<string, unknown>,
  Events = Record<string, unknown>,
> extends HTMLElement {
  private _internals!: ElementInternals
  private _contentObserver: MutationObserver | null = null
  /** True after the first successful connectedCallback completes. */
  private _initialized: boolean = false
  /** Container div created on first connect; reused on subsequent connects. */
  private _container: HTMLElement | null = null
  /**
   * Opt-in reactive adapter. Lazy-allocated on first `this.reactive`
   * access, disposed on `disconnectedCallback`, re-allocated on next
   * access after reconnect. Subclasses that never touch `this.reactive`
   * pay zero allocation cost — `notifyProps`/`notifyContent` short-circuit
   * on the null guard.
   */
  private _reactive: ReactiveAdapterImpl<Props, Events> | null = null
  /**
   * Cached results of the most recent `parseProps` + `validateProps`
   * pass. Set by `connectedCallback` and `attributeChangedCallback`.
   * Read by `get reactive()` to avoid re-parsing on lazy allocation —
   * means `validateProps` only ever runs once per attribute change,
   * even for consumers that touch `this.reactive` inside `onMount`.
   */
  private _lastProps: Props | null = null
  private _lastErrors: readonly string[] = []
  private _lastContent: string | null = null

  /**
   * Phantom field to retain the `Events` type parameter so it shows up in
   * type errors / `Reflect.get` shape. Adapter typing reads it indirectly
   * via the generic.
   * @internal
   */
  declare readonly _events: Events

  /**
   * Override to provide the component's configuration.
   * Must be static because `observedAttributes` reads it before construction.
   *
   * Specify the generic to get typed `validateProps`:
   * ```ts
   * static get wippyConfig(): WippyElementConfig<MyProps> { ... }
   * ```
   */
  static get wippyConfig(): WippyElementConfig {
    return { propsSchema: { properties: {} } }
  }

  /**
   * Derived from the props schema + any `extraObservedAttributes`.
   */
  static get observedAttributes(): string[] {
    const config = this.wippyConfig
    const schemaAttrs = Object.keys(config.propsSchema.properties)
    const extra = config.extraObservedAttributes ?? []
    return [...schemaAttrs, ...extra]
  }

  constructor() {
    super()
    this._internals = this.attachInternals()
  }

  /**
   * Panel-scoped `host` wrapper attached by the managed-layout shell's
   * content resolvers (`ComponentResolver` / `WebComponentPackageLoader`).
   *
   * Inside a managed-layout panel, this is a wrapper around the universal
   * `host` API where context-aware calls (`layout.broadcast / send / on`)
   * are routed through the panel-bound bus — so `sourcePanelId` is
   * attributed correctly without postMessage indirection. Layout
   * mutations and other host methods pass through unchanged.
   *
   * `null` outside a managed-layout context (compat shell, chat sidebar,
   * standalone playground). Subclass code that needs a host in those
   * cases can fall back to `import { host } from '@wippy-fe/proxy'`.
   */
  get host(): ReturnType<typeof getWippyHost> {
    return getWippyHost(this)
  }

  /**
   * Emit a CustomEvent that bubbles and crosses shadow DOM boundaries.
   */
  protected emitEvent(eventName: string, detail?: unknown): void {
    this.dispatchEvent(new CustomEvent(eventName, {
      bubbles: true,
      composed: true,
      detail,
    }))
  }

  /**
   * Opt-in reactive adapter — framework-agnostic. Subscribe to prop
   * changes, content changes, or emit typed events from a non-Vue
   * consumer without re-rolling reactivity.
   *
   * ```ts
   * class MyEl extends WippyElement<{ count: number }, { tick: { n: number } }> {
   *   protected onMount() {
   *     const ctrl = new AbortController()
   *     this.reactive.props.subscribe(({ count }) => {
   *       this.shadowRoot!.querySelector('.n')!.textContent = String(count)
   *     }, { signal: ctrl.signal, immediate: true })
   *   }
   *   tick(n: number) { this.reactive.events.emit('tick', { n }) }
   * }
   * ```
   *
   * Allocation cost is zero unless this getter is touched. Disposed on
   * `disconnectedCallback`; a fresh adapter is allocated on the next
   * access after reconnect.
   */
  protected get reactive(): ReactiveAdapter<Props, Events> {
    if (!this._reactive) {
      const config = (this.constructor as typeof WippyElement).wippyConfig
      const hasContent = !!config.contentTemplate
      // Reuse the cached parse result from the most recent
      // `connectedCallback` / `attributeChangedCallback` whenever we
      // have one; otherwise fall back to a fresh parse (this happens
      // when `reactive` is touched before the element is ever
      // connected — rare but legal).
      let props: Props
      let errors: readonly string[]
      if (this._lastProps !== null) {
        props = this._lastProps
        errors = this._lastErrors
      }
      else {
        const parsed = parseProps(this, config.propsSchema)
        if (config.validateProps) {
          parsed.errors.push(...config.validateProps(parsed.props))
        }
        props = parsed.props as Props
        errors = parsed.errors
        this._lastProps = props
        this._lastErrors = errors
      }
      const content = hasContent
        ? (this._lastContent ?? this._extractContent(config.contentTemplate!))
        : null
      if (hasContent && this._lastContent === null)
        this._lastContent = content
      this._reactive = new ReactiveAdapterImpl<Props, Events>(
        { props, errors, content, hasContent },
        this.emitEvent.bind(this),
      )
    }
    return this._reactive
  }

  // ── Lifecycle ──────────────────────────────────────────────

  connectedCallback(): void {
    this._internals.states.add('loading')
    try {
      const config = (this.constructor as typeof WippyElement).wippyConfig
      const isRemount = this._initialized

      // 1. Shadow DOM (guard against reconnect — attachShadow throws if called twice)
      const shadow = this.shadowRoot ?? this.attachShadow({ mode: config.shadowMode ?? 'open' })

      let container: HTMLElement
      if (!isRemount) {
        // 2. Early hook — customize shadow before CSS/container
        this.onInit(shadow)

        // 3. Inline CSS
        if (config.inlineCss) {
          injectInlineCss(shadow, config.inlineCss)
        }

        // 4. Host CSS (async, non-blocking)
        if (config.hostCssKeys === undefined || config.hostCssKeys.length > 0) {
          loadHostCss(shadow, config.hostCssKeys)
        }

        // 5. Container
        container = document.createElement('div')
        const classes = config.containerClasses ?? []
        if (classes.length > 0) {
          container.classList.add(...classes)
        }
        shadow.appendChild(container)
        this._container = container

        // 6. Icons
        addIcons(addCollection)
      }
      else {
        // Reconnect path — reuse the existing shadow children + container.
        // Skip CSS/icon/container setup so we don't accumulate duplicate
        // `<style>` and container `<div>` siblings on every detach/reattach.
        // The framework adapter decides whether to remount on the existing
        // container or recreate its app instance.
        container = this._container!
      }

      // 7. Parse initial props + custom validation
      const { props, errors } = parseProps(this, config.propsSchema)
      if (config.validateProps) {
        errors.push(...config.validateProps(props))
      }
      const typedProps = props as Props
      // Cache so a lazy `get reactive()` call from inside `onMount`
      // doesn't re-parse / re-validate.
      this._lastProps = typedProps
      this._lastErrors = errors

      // 7b. Extract children content (if contentTemplate configured)
      let initialContent: string | null = null
      if (config.contentTemplate) {
        initialContent = this._extractContent(config.contentTemplate)
        this._lastContent = initialContent
        this._contentObserver = new MutationObserver(() => {
          const content = this._extractContent(config.contentTemplate!)
          this._lastContent = content
          // Fan out to the reactive adapter first so subclass overrides of
          // `onContentChanged` that read `this.reactive.content.value` see
          // the new value. No-op when the adapter hasn't been allocated.
          this._reactive?.notifyContent(content)
          this.onContentChanged(content)
        })
        this._contentObserver.observe(this, {
          childList: true,
          characterData: true,
          subtree: true,
        })
      }

      // 8. Framework mount (first time) or remount (reconnect)
      this.onMount(shadow, container, typedProps, errors, initialContent, isRemount)

      // 9. Ready
      this._internals.states.delete('loading')
      this._internals.states.add('ready')

      // First-connect bookkeeping after a clean mount.
      if (!isRemount) {
        this._initialized = true
      }

      // 10. Post-mount hook
      this.onReady()

      // 11. Emit load
      this.emitEvent('load')
    }
    catch (error) {
      this.onError(error)
      this._internals.states.delete('loading')
      this._internals.states.add('error')
      this.emitEvent('error', {
        message: error instanceof Error ? error.message : String(error),
        error,
      })
    }
  }

  disconnectedCallback(): void {
    if (this._contentObserver) {
      this._contentObserver.disconnect()
      this._contentObserver = null
    }
    this.onUnmount()
    this.emitEvent('unload')
    this._internals.states.clear()
    // Drop the reactive adapter so subscribers from this attachment are
    // cleared and a fresh adapter is allocated on the next `this.reactive`
    // access (i.e. after reconnect).
    this._reactive?.dispose()
    this._reactive = null
    // Clear cached parse state — `connectedCallback` re-populates on
    // reconnect; before then, a lazy `get reactive()` access should
    // re-parse from current attributes (rare path).
    this._lastProps = null
    this._lastErrors = []
    this._lastContent = null
    // Drop panel-context wires so a detached element held by a
    // consumer (or re-inserted into a different panel) doesn't carry
    // stale wires that would silently misattribute. The resolver
    // re-installs them on the next mount.
    delete (this as unknown as { __wippyHost?: unknown }).__wippyHost
    delete (this as unknown as { __wippyHostBus?: unknown }).__wippyHostBus
  }

  attributeChangedCallback(_name: string, oldVal: string | null, newVal: string | null): void {
    if (oldVal === newVal)
      return
    const config = (this.constructor as typeof WippyElement).wippyConfig
    const { props, errors } = parseProps(this, config.propsSchema)
    if (config.validateProps) {
      errors.push(...config.validateProps(props))
    }
    const typedProps = props as Props
    this._lastProps = typedProps
    this._lastErrors = errors
    // Fan out to the reactive adapter BEFORE the legacy hook so subclasses
    // that override `onPropsChanged` AND read `this.reactive.props.value`
    // inside it see consistent state. No-op when the adapter hasn't been
    // lazy-allocated.
    this._reactive?.notifyProps(typedProps, errors)
    this.onPropsChanged(typedProps, errors)
  }

  // ── Hooks ──────────────────────────────────────────────────

  /** Called right after shadow DOM is attached, before CSS or container. */
  protected onInit(_shadow: ShadowRoot): void {}

  /**
   * Called after shadow DOM, CSS, and container are ready. Mount your
   * framework here.
   *
   * Invoked on first connect AND on every subsequent reconnect (move-style
   * DOM op: detach → reattach). On reconnect the same `container` instance
   * is reused. Adapters that hold a framework app handle should either
   * detect `isRemount === true` and re-mount on the existing container, or
   * leave the previous app intact across the detach/reattach cycle.
   */
  protected abstract onMount(
    shadow: ShadowRoot,
    container: HTMLElement,
    initialProps: Props,
    initialErrors: string[],
    initialContent?: string | null,
    isRemount?: boolean,
  ): void

  /** Called after internals state is set to ready, before the `load` event. */
  protected onReady(): void {}

  /** Called when connectedCallback throws. Default logs to console. */
  protected onError(error: unknown): void {
    console.error(`${this.constructor.name} initialization failed:`, error)
  }

  /** Called during disconnectedCallback — clean up framework resources. */
  protected abstract onUnmount(): void

  /** Called when observed attributes change. Override to update framework state. */
  protected onPropsChanged(_props: Props, _errors: string[]): void {}

  /**
   * Extract text from a child `<template data-type="...">` element.
   * Uses `.content.textContent` since `<template>` stores content in a DocumentFragment.
   */
  private _extractContent(dataType: string): string | null {
    const tpl = this.querySelector(`template[data-type="${dataType}"]`) as HTMLTemplateElement | null
    return tpl?.content.textContent?.trim() ?? null
  }

  /** Called when child `<template>` content changes. Override to update framework state. */
  protected onContentChanged(_content: string | null): void {}
}

export { define }
